class Solution {
    public ListNode removeZeroSumSublists(ListNode head) {
        ListNode dummy = new ListNode(0);
        dummy.next = head;
        int prefix = 0;
        Map<Integer, ListNode> seen = new HashMap<>();
        seen.put(0, dummy);
        while (head != null) {
            prefix += head.val;
            if (seen.containsKey(prefix)) {
                ListNode node = seen.get(prefix);
                ListNode tmp = node.next;
                int tmpPrefix = prefix + tmp.val;
                while (tmp != head) {
                    seen.remove(tmpPrefix);
                    tmp = tmp.next;
                    tmpPrefix += tmp.val;
                }
                node.next = head.next;
            } else {
                seen.put(prefix, head);
            }
            head = head.next;
        }
        return dummy.next;
    }
}
